        updated = updated.replace("Гей, бідны лемкы", "Г ей, бідны лемкы")
        updated = updated.replace("В Зеленій Горі плечы гнут", "В Зеленій Г орі плечы гнут")
        updated = updated.replace("А в рідній нашій Лемковині", "А в рідній нашій лемковині")
        updated = updated.replace("\nІнспірациі\n", "\nIнспІрациІ • InspIracje\n")
        if updated != result:
            applied.append("rrb_displaced_lemko_poetry_typography")
